-- Migración 154: forms-align · siembra correctiva 1:1 legacy + soporte renderer avanzado (Zafacones).
-- Generada por scratchpad/gen_forms_align.py. Idempotente (order_index absolutos; disclaimers delete+insert).
-- Cero cambios en pricing/RPCs: selects usan values numéricos '0'..'6' (mismo semántico que number).

-- === schema ===
alter table public.tenant_order_forms
  add column if not exists submit_button_label_es text,
  add column if not exists submit_button_label_en text,
  add column if not exists cancel_button_label_es text default 'Cancelar',
  add column if not exists cancel_button_label_en text default 'Cancel',
  add column if not exists show_summary boolean not null default true,
  add column if not exists summary_footer_es text,
  add column if not exists summary_footer_en text;
alter table public.tenant_order_form_fields
  add column if not exists group_description_es text,
  add column if not exists group_description_en text;
alter table public.tenant_order_form_fields drop constraint if exists tenant_order_form_fields_kind_check;
alter table public.tenant_order_form_fields add constraint tenant_order_form_fields_kind_check
  check (kind in ('text','email','tel','textarea','select','radio','checkbox','number','date',
    'address_block','matrix','addons_group','repeatable_group','file_upload','disclaimer'));


